proof:
have h_check : ∀ (args : Vector (ZMod p) w) (i : ℕ) (h : i < w) (h' : args[i] ≠ 0) (h'' : args[i] ≠ 1), (assert_bits_e args cs).eval = .n := by
  intros args i h h' h'';
  have h_check : ∀ (args : Vector (ZMod p) w) (i : ℕ) (h : i < w) (h' : args[i] ≠ 0) (h'' : args[i] ≠ 1), (Vector.foldl (fun (acc : Cs p (ZMod p)) (b : ZMod p) => .eq0 (.v b * (.c 1 - .v b)) acc) cs args).eval = .n := by
    intros args i h h' h''; induction args using Vector.recOn ; simp_all +decide [ Vector.foldl ] ;
    -- Since `args[i]` is not 0 or 1, the check for `args[i]` will fail, leading to `denotation.n`. We can use the fact that `args[i]` is not 0 or 1 to show that the fold will eventually reach a point where the check fails.
    have h_fold : ∀ (args : List (ZMod p)) (cs : Cs p (ZMod p)), (∃ b ∈ args, b ≠ 0 ∧ b ≠ 1) → (List.foldl (fun (acc : Cs p (ZMod p)) (b : ZMod p) => Cs.eq0 (Exp.v b * (Exp.c 1 - Exp.v b)) acc) cs args).eval = .n := by
      intros args cs h; induction args using List.reverseRecOn <;> simp_all +decide [ List.foldl_append ] ;
      unfold Cs.eval; simp_all +decide [ Exp.eval ] ;
      grind +ring;
    convert h_fold ( Array.toList ‹_› ) cs _;
    · grind;
    · exact ⟨ _, by simp, h', h'' ⟩;
  exact h_check args i h h' h'';
exact h_check args i h h' h''

